revision.text:
{{navbox
| name   = IPA templates
| title  = [[International Phonetic Alphabet|IPA]] templates
| state  = {{{state<includeonly>|expanded</includeonly>}}}
| bodyclass = hlist

| group1 = Inline
| list1  = child

 | 1_group1 = Formatting
 | 1_list1 =
* {{tl|IPA}}
* {{tl|IPA link}}
* {{tl|IPAblink}}&nbsp;{{IPA|[a]}}
* {{tl|IPAslink}}&nbsp;{{IPA|/a/}}
* {{tl|IPAalink}}&nbsp;{{angbr IPA|a}}
* {{tl|IPAplink}}
* {{tl|angbr IPA}}
* {{tl|IPA double slash}}
* {{tl|Chinese tone letter}}
* {{tl|Audio-IPA}}

| 1_group2 = Conversion
| 1_list2 =
<!-- IPAc-xx templates used in more than 100 articles as of Sept 2023 -->
* {{tl|IPAc-en}}
* {{tl|IPAc-cmn}}
* {{tl|IPAc-hu}}
* {{tl|IPAc-pl}}
* {{tl|IPAc-yue}}
* {{tls|X-SAMPA to IPA}}

| 1_group3 = Maintenance
| 1_list3 =
* {{tl|Needs IPA}}
* {{tl|Pronunciation needed}}

| group2 = Charts
| list2 =
* {{tl|IPA vowels}}
* {{tl|IPA pulmonic consonants}}
* {{tl|IPA non-pulmonic consonants}}
* {{tl|IPA co-articulated consonants}}
* {{tl|IPA affricates}}

| group3 = Guidance
| list3 =
* {{tl|IPA navigation}}
* {{tl|Infobox IPA}}
* {{tl|IPA notice}}
* {{tl|WikiIPA}}
* {{tl|IPA key}}
* {{tl|IPA keys}}
* {{tl|IPA language category}}

| group4 = Meta templates
| list4 =
* {{tl|IPA symbol}}
* {{tl|IPA audio link}}
* {{tl|IPA common}}
* {{tl|IPA soundbox}}
* {{tl|Usage of IPA templates}}
* {{tl|IPA notice/msg}}

}}<noinclude>{{documentation}}</noinclude>

